//! Extended procedural oracles — instant, no-LLM answers beyond arithmetic:
//! boolean logic + truth tables, probability/combinatorics + the buleyean God
//! Formula, sovereign constants (monster numbers, the Bule unit, gnostic time),
//! date/time math, equation solving, and string ops. Each `try_*` is
//! conservative and returns None on anything it doesn't confidently own, so the
//! umbrella falls through cleanly.

use crate::calc::format_number;
use std::collections::HashMap;

/// Try every extended oracle in turn.
pub fn try_oracle(line: &str) -> Option<String> {
    try_logic(line)
        .or_else(|| try_prob(line))
        .or_else(|| try_solve(line))
        .or_else(|| try_solve_numeric(line))
        .or_else(|| try_gnosis(line))
        .or_else(|| try_datetime(line))
        .or_else(|| try_string(line))
}

// ── equation solver: single-variable linear + quadratic ──────────────────────

/// `solve 2x+3=11` → `x = 4`; `solve x^2-5x+6=0` → `x = 3 or 2`.
/// Samples f(x)=lhs−rhs at fixed points, fits a degree-≤2 polynomial exactly,
/// then solves in closed form. Returns None for higher degree / non-polynomial /
/// inequalities (those are omega/ring territory).
fn try_solve(line: &str) -> Option<String> {
    let s = line.trim();
    let s = s.strip_prefix("solve ").or_else(|| s.strip_prefix("Solve "))?;
    let s = s.trim().trim_end_matches(['?', '.']).trim();
    if s.contains('<') || s.contains('>') {
        return None; // inequality → omega, not closed-form solve
    }
    let (lhs, rhs) = s.split_once('=')?;
    if rhs.contains('=') {
        return None;
    }
    let var = detect_var(s)?;
    let expr = format!("({})-({})", lhs.trim(), rhs.trim());

    let f0 = eval_at(&expr, var, 0.0)?;
    let f1 = eval_at(&expr, var, 1.0)?;
    let fm = eval_at(&expr, var, -1.0)?;
    let f2 = eval_at(&expr, var, 2.0)?;

    let a = (f1 + fm) / 2.0 - f0;
    let b = (f1 - fm) / 2.0;
    let c = f0;
    // Confirm degree ≤ 2: the fitted polynomial must reproduce a 4th sample.
    if (4.0 * a + 2.0 * b + c - f2).abs() > 1e-6 {
        return None;
    }

    let eps = 1e-9;
    if a.abs() < eps {
        if b.abs() < eps {
            return None; // 0=0 or contradiction — not a solve
        }
        return Some(format!("{var} = {}", format_number(-c / b)));
    }
    let disc = b * b - 4.0 * a * c;
    if disc < -eps {
        return Some(format!("no real solution (discriminant {})", format_number(disc)));
    }
    let disc = disc.max(0.0);
    let sq = disc.sqrt();
    let x1 = (-b + sq) / (2.0 * a);
    let x2 = (-b - sq) / (2.0 * a);
    if (x1 - x2).abs() < 1e-9 {
        Some(format!("{var} = {}", format_number(x1)))
    } else {
        let (hi, lo) = if x1 >= x2 { (x1, x2) } else { (x2, x1) };
        Some(format!("{var} = {} or {}", format_number(hi), format_number(lo)))
    }
}

/// General single-variable numeric solver — the WolframAlpha-style fallback for
/// equations `try_solve` declines (cubics+, roots, transcendental). Works with
/// or without a `solve ` prefix: `r^3=16` → `r = 2.5198`, `2^x=8` → `x = 3`.
/// Samples f(x)=lhs−rhs across a wide range, brackets sign changes, and bisects.
fn try_solve_numeric(line: &str) -> Option<String> {
    let s = line.trim();
    let s = s
        .strip_prefix("solve ")
        .or_else(|| s.strip_prefix("Solve "))
        .unwrap_or(s);
    let s = s
        .trim()
        .trim_end_matches(['?', '.'])
        .trim();
    if s.contains('<') || s.contains('>') || s.contains("==") {
        return None;
    }
    let (lhs, rhs) = s.split_once('=')?;
    if rhs.contains('=') || lhs.trim().is_empty() || rhs.trim().is_empty() {
        return None;
    }
    let var = detect_var(s)?;
    let expr = format!("({})-({})", lhs.trim(), rhs.trim());
    let f = |x: f64| eval_at(&expr, var, x);
    // Require the expression to evaluate at a couple of probe points.
    f(0.0)?;
    f(1.0)?;

    let lo = -1000.0_f64;
    let hi = 1000.0_f64;
    let steps = 4000;
    let dx = (hi - lo) / steps as f64;
    let mut roots: Vec<f64> = Vec::new();
    let mut prev_x = lo;
    let mut prev_f = f(lo)?;
    let mut i = 1;
    while i <= steps {
        let x = lo + dx * i as f64;
        if let Some(fx) = f(x) {
            if prev_f == 0.0 {
                push_root(&mut roots, prev_x);
            }
            if (prev_f < 0.0 && fx > 0.0) || (prev_f > 0.0 && fx < 0.0) {
                if let Some(r) = bisect_root(&f, prev_x, x) {
                    push_root(&mut roots, r);
                }
            }
            prev_x = x;
            prev_f = fx;
        }
        i += 1;
    }
    if roots.is_empty() {
        return None;
    }
    roots.sort_by(|a, b| b.partial_cmp(a).unwrap_or(std::cmp::Ordering::Equal));
    roots.truncate(4);
    let parts: Vec<String> = roots.iter().map(|r| format_number(*r)).collect();
    Some(format!("{var} = {}", parts.join(" or ")))
}

fn bisect_root<F: Fn(f64) -> Option<f64>>(f: &F, a0: f64, b0: f64) -> Option<f64> {
    let mut a = a0;
    let mut b = b0;
    let mut fa = f(a)?;
    for _ in 0..80 {
        let m = (a + b) / 2.0;
        let fm = f(m)?;
        if fm.abs() < 1e-11 || (b - a).abs() < 1e-13 {
            return Some(m);
        }
        if (fa < 0.0) == (fm < 0.0) {
            a = m;
            fa = fm;
        } else {
            b = m;
        }
    }
    Some((a + b) / 2.0)
}

fn push_root(roots: &mut Vec<f64>, r: f64) {
    if !r.is_finite() {
        return;
    }
    let rounded = (r * 1e6).round() / 1e6;
    if roots.iter().all(|&e| (e - rounded).abs() > 1e-4) {
        roots.push(rounded);
    }
}

/// Find the single algebraic variable: a lone letter (not part of a function
/// name) other than the constant `e`. Returns None unless exactly one is present.
fn detect_var(s: &str) -> Option<char> {
    let chars: Vec<char> = s.to_lowercase().chars().collect();
    let mut found: Option<char> = None;
    for (i, &c) in chars.iter().enumerate() {
        if !c.is_ascii_alphabetic() || c == 'e' {
            continue;
        }
        let prev_alpha = i > 0 && chars[i - 1].is_ascii_alphabetic();
        let next_alpha = i + 1 < chars.len() && chars[i + 1].is_ascii_alphabetic();
        if prev_alpha || next_alpha {
            continue; // inside a word (function/constant name)
        }
        match found {
            Some(v) if v != c => return None, // two distinct variables
            _ => found = Some(c),
        }
    }
    found
}

/// Evaluate `expr` with `var` bound to `val`, inserting implicit multiplication.
fn eval_at(expr: &str, var: char, val: f64) -> Option<f64> {
    let repl = format!("({val})");
    let substituted: String = expr
        .chars()
        .map(|ch| {
            if ch.eq_ignore_ascii_case(&var) {
                repl.clone()
            } else {
                ch.to_string()
            }
        })
        .collect();
    crate::calc::eval_expr(&insert_implicit_mult(&substituted))
}

/// Insert `*` across paren boundaries so `2(3)`, `)2`, `)(` parse as products.
fn insert_implicit_mult(s: &str) -> String {
    let chars: Vec<char> = s.chars().collect();
    let mut out = String::new();
    for (i, &c) in chars.iter().enumerate() {
        out.push(c);
        if i + 1 >= chars.len() {
            break;
        }
        let mut j = i + 1;
        while j < chars.len() && chars[j] == ' ' {
            j += 1;
        }
        if j >= chars.len() {
            break;
        }
        let next = chars[j];
        let val_end = c.is_ascii_digit() || c == '.' || c == ')';
        let val_start = next.is_ascii_digit() || next == '.';
        if (val_end && next == '(') || (c == ')' && val_start) {
            out.push('*');
        }
    }
    out
}

// ── boolean logic + truth tables ─────────────────────────────────────────────

#[derive(Clone, PartialEq, Debug)]
enum LTok {
    Var(String),
    Const(bool),
    Not,
    And,
    Or,
    Xor,
    Implies,
    Iff,
    LParen,
    RParen,
}

fn try_logic(line: &str) -> Option<String> {
    let s = line.trim().to_lowercase();
    let s = s.trim_end_matches(['?', '.']).trim();
    let toks = logic_lex(s)?;
    // Require at least one boolean operator, else it isn't a logic expression.
    if !toks.iter().any(|t| {
        matches!(
            t,
            LTok::Not | LTok::And | LTok::Or | LTok::Xor | LTok::Implies | LTok::Iff
        )
    }) {
        return None;
    }
    let mut vars: Vec<String> = Vec::new();
    for t in &toks {
        if let LTok::Var(v) = t {
            if !vars.contains(v) {
                vars.push(v.clone());
            }
        }
    }
    if vars.is_empty() {
        let env = HashMap::new();
        let v = LogicParser::new(&toks, &env).parse()?;
        return Some(if v { "true" } else { "false" }.to_string());
    }
    if vars.len() > 12 {
        return None;
    }
    let n = vars.len();
    let rows = 1u32 << n;
    let mut models = 0u32;
    for mask in 0..rows {
        let mut env = HashMap::new();
        for (i, v) in vars.iter().enumerate() {
            env.insert(v.clone(), (mask >> i) & 1 == 1);
        }
        if LogicParser::new(&toks, &env).parse()? {
            models += 1;
        }
    }
    Some(if models == rows {
        format!("tautology (true for all {rows} assignments)")
    } else if models == 0 {
        "contradiction (unsatisfiable)".to_string()
    } else {
        format!("satisfiable: true in {models}/{rows} assignments")
    })
}

fn logic_lex(s: &str) -> Option<Vec<LTok>> {
    let mut out = Vec::new();
    let bytes = s.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        let rest = &s[i..];
        let c = bytes[i] as char;
        if c.is_whitespace() {
            i += 1;
            continue;
        }
        if rest.starts_with("<->") || rest.starts_with("<=>") {
            out.push(LTok::Iff);
            i += 3;
            continue;
        }
        if rest.starts_with("->") || rest.starts_with("=>") {
            out.push(LTok::Implies);
            i += 2;
            continue;
        }
        if rest.starts_with("&&") {
            out.push(LTok::And);
            i += 2;
            continue;
        }
        if rest.starts_with("||") {
            out.push(LTok::Or);
            i += 2;
            continue;
        }
        match c {
            '∧' => { out.push(LTok::And); i += c.len_utf8(); continue; }
            '∨' => { out.push(LTok::Or); i += c.len_utf8(); continue; }
            '¬' | '~' => { out.push(LTok::Not); i += c.len_utf8(); continue; }
            '⊕' => { out.push(LTok::Xor); i += c.len_utf8(); continue; }
            '→' => { out.push(LTok::Implies); i += c.len_utf8(); continue; }
            '↔' => { out.push(LTok::Iff); i += c.len_utf8(); continue; }
            '!' => { out.push(LTok::Not); i += 1; continue; }
            '&' => { out.push(LTok::And); i += 1; continue; }
            '|' => { out.push(LTok::Or); i += 1; continue; }
            '^' => { out.push(LTok::Xor); i += 1; continue; }
            '(' => { out.push(LTok::LParen); i += 1; continue; }
            ')' => { out.push(LTok::RParen); i += 1; continue; }
            _ => {}
        }
        if c.is_ascii_alphabetic() {
            let start = i;
            while i < bytes.len()
                && ((bytes[i] as char).is_ascii_alphanumeric() || bytes[i] == b'_')
            {
                i += 1;
            }
            out.push(match &s[start..i] {
                "and" => LTok::And,
                "or" => LTok::Or,
                "not" => LTok::Not,
                "xor" => LTok::Xor,
                "implies" | "imp" => LTok::Implies,
                "iff" | "equiv" => LTok::Iff,
                "true" => LTok::Const(true),
                "false" => LTok::Const(false),
                w => LTok::Var(w.to_string()),
            });
            continue;
        }
        return None;
    }
    Some(out)
}

struct LogicParser<'a> {
    toks: &'a [LTok],
    pos: usize,
    env: &'a HashMap<String, bool>,
}

impl<'a> LogicParser<'a> {
    fn new(toks: &'a [LTok], env: &'a HashMap<String, bool>) -> Self {
        Self { toks, pos: 0, env }
    }
    fn peek(&self) -> Option<&LTok> {
        self.toks.get(self.pos)
    }
    fn parse(&mut self) -> Option<bool> {
        let v = self.iff()?;
        if self.pos == self.toks.len() {
            Some(v)
        } else {
            None
        }
    }
    fn iff(&mut self) -> Option<bool> {
        let mut a = self.implies()?;
        while self.peek() == Some(&LTok::Iff) {
            self.pos += 1;
            let b = self.implies()?;
            a = a == b;
        }
        Some(a)
    }
    fn implies(&mut self) -> Option<bool> {
        let a = self.or()?;
        if self.peek() == Some(&LTok::Implies) {
            self.pos += 1;
            let b = self.implies()?; // right-associative
            return Some(!a || b);
        }
        Some(a)
    }
    fn or(&mut self) -> Option<bool> {
        let mut a = self.xor()?;
        while self.peek() == Some(&LTok::Or) {
            self.pos += 1;
            let b = self.xor()?;
            a = a || b;
        }
        Some(a)
    }
    fn xor(&mut self) -> Option<bool> {
        let mut a = self.and()?;
        while self.peek() == Some(&LTok::Xor) {
            self.pos += 1;
            let b = self.and()?;
            a ^= b;
        }
        Some(a)
    }
    fn and(&mut self) -> Option<bool> {
        let mut a = self.not()?;
        while self.peek() == Some(&LTok::And) {
            self.pos += 1;
            let b = self.not()?;
            a = a && b;
        }
        Some(a)
    }
    fn not(&mut self) -> Option<bool> {
        if self.peek() == Some(&LTok::Not) {
            self.pos += 1;
            return Some(!self.not()?);
        }
        self.atom()
    }
    fn atom(&mut self) -> Option<bool> {
        match self.peek().cloned()? {
            LTok::LParen => {
                self.pos += 1;
                let v = self.iff()?;
                if self.peek() != Some(&LTok::RParen) {
                    return None;
                }
                self.pos += 1;
                Some(v)
            }
            LTok::Const(b) => {
                self.pos += 1;
                Some(b)
            }
            LTok::Var(name) => {
                self.pos += 1;
                self.env.get(&name).copied()
            }
            _ => None,
        }
    }
}

// ── probability + combinatorics + buleyean ───────────────────────────────────

fn try_prob(line: &str) -> Option<String> {
    let lower = line.trim().to_lowercase();
    let s = lower.trim_end_matches(['?', '.']).trim();

    if let Some((n, k)) = parse_choose(s) {
        return Some(format_number(ncr(n, k)));
    }
    if let Some((n, k)) = parse_permute(s) {
        return Some(format_number(npr(n, k)));
    }
    if let Some(rest) = s.strip_prefix("prob ").or_else(|| s.strip_prefix("buleyean ")) {
        return buleyean_answer(rest);
    }
    if let Some(rest) = s.strip_prefix("entropy ") {
        return entropy_answer(rest);
    }
    if let Some(p) = parse_odds(s) {
        return Some(format!("{} ({}%)", format_number(p), format_number(p * 100.0)));
    }
    None
}

fn ncr(n: f64, k: f64) -> f64 {
    if k < 0.0 || k > n {
        return 0.0;
    }
    let k = k.min(n - k);
    let mut acc = 1f64;
    let mut i = 0f64;
    while i < k {
        acc = acc * (n - i) / (i + 1.0);
        i += 1.0;
    }
    acc.round()
}

fn npr(n: f64, k: f64) -> f64 {
    if k < 0.0 || k > n {
        return 0.0;
    }
    let mut acc = 1f64;
    let mut i = 0f64;
    while i < k {
        acc *= n - i;
        i += 1.0;
    }
    acc
}

/// "n choose k", "nCk", "C(n,k)".
fn parse_choose(s: &str) -> Option<(f64, f64)> {
    if let Some(idx) = s.find(" choose ") {
        let n = s[..idx].trim().parse().ok()?;
        let k = s[idx + 8..].trim().parse().ok()?;
        return Some((n, k));
    }
    parse_two_arg(s, 'c')
}

/// "n permute k", "nPk", "P(n,k)".
fn parse_permute(s: &str) -> Option<(f64, f64)> {
    if let Some(idx) = s.find(" permute ") {
        let n = s[..idx].trim().parse().ok()?;
        let k = s[idx + 9..].trim().parse().ok()?;
        return Some((n, k));
    }
    parse_two_arg(s, 'p')
}

/// "nCk"/"nPk" or "C(n,k)"/"P(n,k)".
fn parse_two_arg(s: &str, op: char) -> Option<(f64, f64)> {
    let s = s.replace(' ', "");
    // C(n,k) form
    if let Some(rest) = s.strip_prefix(op).and_then(|r| r.strip_prefix('(')) {
        let inner = rest.strip_suffix(')')?;
        let (a, b) = inner.split_once(',')?;
        return Some((a.parse().ok()?, b.parse().ok()?));
    }
    // nCk form
    let idx = s.find(op)?;
    let n = s[..idx].parse().ok()?;
    let k = s[idx + 1..].parse().ok()?;
    Some((n, k))
}

/// "3:1" or "3 to 1" odds → win probability.
fn parse_odds(s: &str) -> Option<f64> {
    let (a, b) = if let Some((a, b)) = s.split_once(':') {
        (a, b)
    } else if let Some(idx) = s.find(" to ") {
        // require the surrounding to be "<num> to <num> [odds]"
        let rhs = s[idx + 4..].trim().trim_end_matches(" odds").trim();
        (s[..idx].trim(), rhs)
    } else {
        return None;
    };
    let a: f64 = a.trim().trim_start_matches("odds").trim().parse().ok()?;
    let b: f64 = b.trim().parse().ok()?;
    if a + b == 0.0 {
        return None;
    }
    Some(a / (a + b))
}

/// `prob <c0> <c1> …` — the buleyean God Formula: w_i = T − v_i + 1, normalized;
/// the "bule number" = max(counts) − min(counts). Matches eval_bridge's `prob`.
fn buleyean_answer(rest: &str) -> Option<String> {
    let counts: Vec<f64> = rest
        .split(|c: char| c == ',' || c.is_whitespace())
        .filter(|t| !t.is_empty())
        .map(|t| t.parse().ok())
        .collect::<Option<Vec<f64>>>()?;
    if counts.is_empty() {
        return None;
    }
    let total: f64 = counts.iter().sum();
    let weights: Vec<f64> = counts.iter().map(|v| total - v.min(total) + 1.0).collect();
    let wsum: f64 = weights.iter().sum();
    let probs: Vec<String> = weights
        .iter()
        .map(|w| format_number(w / wsum))
        .collect();
    let max = counts.iter().cloned().fold(f64::MIN, f64::max);
    let min = counts.iter().cloned().fold(f64::MAX, f64::min);
    let bule = max - min;
    let weights_s: Vec<String> = weights.iter().map(|w| format_number(*w)).collect();
    Some(format!(
        "weights [{}]  probabilities [{}]  bule {}",
        weights_s.join(", "),
        probs.join(", "),
        format_number(bule)
    ))
}

/// `entropy <p0> <p1> …` — Shannon entropy in bits.
fn entropy_answer(rest: &str) -> Option<String> {
    let ps: Vec<f64> = rest
        .split(|c: char| c == ',' || c.is_whitespace())
        .filter(|t| !t.is_empty())
        .map(|t| t.parse().ok())
        .collect::<Option<Vec<f64>>>()?;
    if ps.is_empty() {
        return None;
    }
    let h: f64 = ps
        .iter()
        .filter(|p| **p > 0.0)
        .map(|p| -p * p.log2())
        .sum();
    Some(format!("{} bits", format_number(h)))
}

// ── sovereign constants + gnostic time ───────────────────────────────────────

fn try_gnosis(line: &str) -> Option<String> {
    let lower = line.trim().to_lowercase();
    let mut s = lower
        .trim_end_matches(['?', '.'])
        .trim();
    for p in ["what is ", "whats ", "what's ", "the value of "] {
        if let Some(r) = s.strip_prefix(p) {
            s = r.trim();
        }
    }
    let s = s.strip_prefix("the ").unwrap_or(s).trim();

    let lookup = match s {
        "monster number" | "leech kissing number" | "leech kissing" => Some("196560"),
        "griess" | "griess dim" | "griess dimension" | "griess algebra dimension" => {
            Some("196884")
        }
        "monster irrep" | "smallest monster irrep" | "monster representation" => Some("196883"),
        "antipodal pairs" | "pair band" => Some("98280"),
        "e8 kissing" | "e8 kissing number" => Some("240"),
        "e8 dim" | "e8 dimension" => Some("248"),
        "dodecagon" | "fermion wall" | "aeon phases" => Some("12"),
        "clinamen" => Some("1"),
        "helix55" | "helix 55" => Some("55"),
        "grassmannian cycle" => Some("66"),
        "monster order digits" => Some("54"),
        _ => None,
    };
    if let Some(v) = lookup {
        return Some(v.to_string());
    }

    if s == "bule unit" || s == "bule" {
        return Some(
            "Bule = (waste, opportunity, diversity); score = waste + opportunity + diversity \
             (a 3-faced cost unit; gnosis-math SpectralNoiseEquilibrium)"
                .to_string(),
        );
    }
    if let Some(rest) = s.strip_prefix("bule of ").or_else(|| s.strip_prefix("bule number ")) {
        let counts: Vec<f64> = rest
            .split(|c: char| c == ',' || c.is_whitespace())
            .filter(|t| !t.is_empty())
            .map(|t| t.parse().ok())
            .collect::<Option<Vec<f64>>>()?;
        if counts.is_empty() {
            return None;
        }
        let max = counts.iter().cloned().fold(f64::MIN, f64::max);
        let min = counts.iter().cloned().fold(f64::MAX, f64::min);
        return Some(format_number(max - min));
    }
    // "god formula <R> <v>" -> R - min(v,R) + 1
    if let Some(rest) = s.strip_prefix("god formula ").or_else(|| s.strip_prefix("godweight ")) {
        let nums: Vec<f64> = rest
            .split(|c: char| c == ',' || c.is_whitespace())
            .filter(|t| !t.is_empty())
            .map(|t| t.parse().ok())
            .collect::<Option<Vec<f64>>>()?;
        if nums.len() == 2 {
            let (r, v) = (nums[0], nums[1]);
            return Some(format_number(r - v.min(r) + 1.0));
        }
    }
    if s == "gnosis time" || s == "gnostic time" {
        return Some(gnosis_time_now());
    }
    None
}

/// Decompose now into the gnostic calendar (picolorenzo = π days; aeon 110 /
/// pleroma 55 / kenoma 10 / sophia 9 / barbelo 1), mirroring get_gnosis_time().
fn gnosis_time_now() -> String {
    let now_ms = chrono::Utc::now().timestamp_millis() as f64;
    let picolorenzo_ms = std::f64::consts::PI * 86400.0 * 1000.0;
    let mut remaining = now_ms / picolorenzo_ms;
    let mut parts = Vec::new();
    for (factor, label) in [(110.0, 'a'), (55.0, 'p'), (10.0, 'k'), (9.0, 's')] {
        let n = (remaining / factor).floor();
        remaining -= n * factor;
        if n > 0.0 {
            parts.push(format!("{}{label}", n as i64));
        }
    }
    parts.push(format!("{}b", remaining.floor() as i64));
    parts.join(" ")
}

// ── date / time math ─────────────────────────────────────────────────────────

fn try_datetime(line: &str) -> Option<String> {
    use chrono::{Datelike, Duration, NaiveDate, Utc};
    let lower = line.trim().to_lowercase();
    let s = lower.trim_end_matches(['?', '.']).trim();

    // "days between A and B"
    if let Some(rest) = s.strip_prefix("days between ") {
        if let Some((a, b)) = rest.split_once(" and ") {
            let da = parse_date(a.trim())?;
            let db = parse_date(b.trim())?;
            return Some(format!("{}", (db - da).num_days().abs()));
        }
    }
    // "days until/since <date>"
    if let Some(rest) = s.strip_prefix("days until ").or_else(|| s.strip_prefix("days till ")) {
        let d = parse_date(rest.trim())?;
        let today = Utc::now().date_naive();
        return Some(format!("{}", (d - today).num_days()));
    }
    if let Some(rest) = s.strip_prefix("days since ") {
        let d = parse_date(rest.trim())?;
        let today = Utc::now().date_naive();
        return Some(format!("{}", (today - d).num_days()));
    }
    // "weekday of <date>" / "what day is <date>"
    for p in ["weekday of ", "what day is ", "day of week "] {
        if let Some(rest) = s.strip_prefix(p) {
            let d = parse_date(rest.trim())?;
            return Some(d.weekday().to_string());
        }
    }
    // "<date> plus/minus N days"
    for (sep, sign) in [(" plus ", 1i64), (" minus ", -1)] {
        if let Some(idx) = s.find(sep) {
            if let Some(d) = parse_date(s[..idx].trim()) {
                let rhs = s[idx + sep.len()..].trim();
                let ndays = rhs
                    .trim_end_matches(" days")
                    .trim_end_matches(" day")
                    .trim()
                    .parse::<i64>()
                    .ok()?;
                let out = d + Duration::days(sign * ndays);
                return Some(out.format("%Y-%m-%d").to_string());
            }
        }
    }
    let _ = NaiveDate::MIN; // keep import used in all cfgs
    None
}

fn parse_date(s: &str) -> Option<chrono::NaiveDate> {
    let s = s.trim();
    for fmt in ["%Y-%m-%d", "%Y/%m/%d", "%m/%d/%Y", "%d/%m/%Y", "%B %d %Y", "%b %d %Y"] {
        if let Ok(d) = chrono::NaiveDate::parse_from_str(s, fmt) {
            return Some(d);
        }
    }
    if s == "today" {
        return Some(chrono::Utc::now().date_naive());
    }
    None
}

// ── string ops ───────────────────────────────────────────────────────────────

fn try_string(line: &str) -> Option<String> {
    use base64::{engine::general_purpose, Engine as _};
    let trimmed = line.trim();
    let lower = trimmed.to_lowercase();

    let with_arg = |verbs: &[&str]| -> Option<String> {
        for v in verbs {
            // case-insensitive prefix, keep the ORIGINAL-case argument
            if lower.starts_with(v) {
                return Some(trimmed[v.len()..].trim().to_string());
            }
        }
        None
    };

    if let Some(a) = with_arg(&["reverse "]) {
        return Some(a.chars().rev().collect());
    }
    if let Some(a) = with_arg(&["uppercase ", "upper ", "upcase "]) {
        return Some(a.to_uppercase());
    }
    if let Some(a) = with_arg(&["lowercase ", "lower ", "downcase "]) {
        return Some(a.to_lowercase());
    }
    if let Some(a) = with_arg(&["length of ", "len of ", "char count "]) {
        return Some(format!("{}", a.chars().count()));
    }
    if let Some(a) = with_arg(&["words in ", "word count "]) {
        return Some(format!("{}", a.split_whitespace().count()));
    }
    if let Some(a) = with_arg(&["base64 decode ", "b64 decode ", "unbase64 "]) {
        let bytes = general_purpose::STANDARD.decode(a.trim()).ok()?;
        return Some(String::from_utf8_lossy(&bytes).into_owned());
    }
    if let Some(a) = with_arg(&["base64 ", "base64 encode ", "b64 "]) {
        return Some(general_purpose::STANDARD.encode(a.as_bytes()));
    }
    None
}

#[cfg(test)]
mod tests {
    use super::try_oracle as t;

    #[test]
    fn logic() {
        assert_eq!(t("p or not p").as_deref(), Some("tautology (true for all 2 assignments)"));
        assert_eq!(t("p and not p").as_deref(), Some("contradiction (unsatisfiable)"));
        assert!(t("p implies q").unwrap().starts_with("satisfiable"));
        assert_eq!(t("true and false").as_deref(), Some("false"));
        assert_eq!(t("not (true and false)").as_deref(), Some("true"));
    }

    #[test]
    fn probability() {
        assert_eq!(t("5 choose 2").as_deref(), Some("10"));
        assert_eq!(t("C(6,3)").as_deref(), Some("20"));
        assert_eq!(t("5 permute 2").as_deref(), Some("20"));
        assert!(t("prob 1 2 3").unwrap().contains("weights"));
        assert_eq!(t("entropy 0.5 0.5").as_deref(), Some("1 bits"));
        assert!(t("3 to 1 odds").unwrap().starts_with("0.75"));
    }

    #[test]
    fn solve() {
        assert_eq!(t("solve 2x+3=11").as_deref(), Some("x = 4"));
        assert_eq!(t("solve x^2-5x+6=0").as_deref(), Some("x = 3 or 2"));
        assert_eq!(t("solve 3y - 9 = 0").as_deref(), Some("y = 3"));
        assert_eq!(t("solve x^2 = 9").as_deref(), Some("x = 3 or -3"));
        assert!(t("solve x^2+1=0").unwrap().starts_with("no real solution"));
        assert_eq!(t("solve x^3=8").as_deref(), Some("x = 2"));
    }

    #[test]
    fn gnosis() {
        assert_eq!(t("monster number").as_deref(), Some("196560"));
        assert_eq!(t("e8 kissing number").as_deref(), Some("240"));
        assert_eq!(t("god formula 5 2").as_deref(), Some("4"));
        assert_eq!(t("bule of 1 2 3").as_deref(), Some("2"));
    }

    #[test]
    fn datetime() {
        assert_eq!(t("days between 2026-01-01 and 2026-12-31").as_deref(), Some("364"));
        assert_eq!(t("weekday of 2026-07-04").as_deref(), Some("Sat"));
        assert_eq!(t("2026-01-01 plus 100 days").as_deref(), Some("2026-04-11"));
    }

    #[test]
    fn strings() {
        assert_eq!(t("reverse hello").as_deref(), Some("olleh"));
        assert_eq!(t("uppercase hello").as_deref(), Some("HELLO"));
        assert_eq!(t("length of hello").as_deref(), Some("5"));
        assert_eq!(t("words in the quick brown fox").as_deref(), Some("4"));
        assert_eq!(t("base64 hi").as_deref(), Some("aGk="));
        assert_eq!(t("base64 decode aGk=").as_deref(), Some("hi"));
    }
}
